(function(window){"use strict";var PING_INTERVAL=25*1e3;var PONG_TIMEOUT=10*1e3;var RECONNECT_BASE=1e3;var RECONNECT_MAX=30*1e3;var SESSION_PING_INTERVAL=10*60*1e3;window.createAuthenticatedWebSocket=function(url,onMessage,onError,onStatusChange){if(!url||typeof url!=="string"){var proto=window.location.protocol==="https:"?"wss:":"ws:";url=proto+"//"+window.location.host+"/ws"}var socket=null;var authenticated=false;var destroyed=false;var reconnectDelay=RECONNECT_BASE;var reconnectTimer=null;var pingTimer=null;var pongTimer=null;var sessionTimer=null;function notifyStatus(connected){if(onStatusChange){try{onStatusChange(connected)}catch(e){}}}function stopPing(){if(pingTimer){clearInterval(pingTimer);pingTimer=null}if(pongTimer){clearTimeout(pongTimer);pongTimer=null}}function startPing(){stopPing();pingTimer=setInterval(function(){if(!socket||socket.readyState!==WebSocket.OPEN)return;socket.send(JSON.stringify({type:"ping"}));pongTimer=setTimeout(function(){console.warn("WebSocket: pong timeout — reconnecting");socket.close()},PONG_TIMEOUT)},PING_INTERVAL)}function startSessionKeepalive(){if(sessionTimer)return;sessionTimer=setInterval(function(){var csrfToken=typeof window._getCsrfToken==="function"?window._getCsrfToken():"";fetch("/ajax",{method:"POST",credentials:"same-origin",headers:{"Content-Type":"application/json","X-CSRF-Token":csrfToken},body:JSON.stringify({command:"ping"})}).then(function(r){if(r.status===401||r.status===403){window.location.href="/login"}}).catch(function(){})},SESSION_PING_INTERVAL)}function stopSessionKeepalive(){if(sessionTimer){clearInterval(sessionTimer);sessionTimer=null}}function scheduleReconnect(){if(destroyed)return;reconnectTimer=setTimeout(function(){reconnectDelay=Math.min(reconnectDelay*2,RECONNECT_MAX);connect()},reconnectDelay)}function connect(){if(destroyed)return;socket=new WebSocket(url);socket.addEventListener("open",function(){var authData={type:"auth",userId:window.WS_USER_ID,token:window.WS_AUTH_TOKEN};if(window.WS_GROUP_ID&&window.WS_GROUP_ID>0){authData.groupId=window.WS_GROUP_ID}socket.send(JSON.stringify(authData))});socket.addEventListener("message",function(event){try{var data=JSON.parse(event.data);if(data.type==="pong"){if(pongTimer){clearTimeout(pongTimer);pongTimer=null}return}if(data.type==="auth_success"){authenticated=true;reconnectDelay=RECONNECT_BASE;notifyStatus(true);startPing();startSessionKeepalive();return}if(data.error){console.error("WebSocket error from server:",data.error);if(onError){try{onError(data.error)}catch(e){}}socket.close();return}if(authenticated){if(onMessage){try{onMessage(data)}catch(e){}}window.dispatchEvent(new CustomEvent("websocket_message",{detail:data}))}}catch(e){console.error("WebSocket message parse error:",e)}});socket.addEventListener("error",function(error){console.error("WebSocket connection error:",error);if(onError){try{onError(error)}catch(e){}}});socket.addEventListener("close",function(){authenticated=false;stopPing();notifyStatus(false);scheduleReconnect()})}connect();return{destroy:function(){destroyed=true;stopPing();stopSessionKeepalive();if(reconnectTimer){clearTimeout(reconnectTimer);reconnectTimer=null}if(socket){socket.close();socket=null}}}}})(window);